    /**
     * Builds the HttpRequest object for createE911Order.
     */
    private HttpRequest buildCreateE911OrderRequest(
            final int accountId,
            final E911OrderPayload body) throws JsonProcessingException, JAXBException {
        //the base uri for api requests
        String baseUri = config.getBaseUri(Server.IRISDEFAULT);

        //prepare query string for API call
        final StringBuilder queryBuilder = new StringBuilder(baseUri
                + "/accounts/{accountId}/e911s");

        //process template parameters
        Map<String, SimpleEntry<Object, Boolean>> templateParameters = new HashMap<>();
        templateParameters.put("accountId",
                new SimpleEntry<Object, Boolean>(accountId, false));
        ApiHelper.appendUrlWithTemplateParameters(queryBuilder, templateParameters);

        //load all headers for the outgoing API request
        Headers headers = new Headers();
        headers.add("user-agent", BaseController.userAgent);
        headers.add("accept", "application/xml");
        headers.add("content-type", "application/xml");

        //prepare and invoke the API call request to fetch the response
        String bodyXml = ApiHelper.serializeXml(body, "E911Order", E911OrderPayload.class);
        HttpRequest request = getClientInstance().postBody(queryBuilder, headers, null, bodyXml);

        // Invoke the callback before request if its not null
        if (getHttpCallback() != null) {
            getHttpCallback().onBeforeRequest(request);
        }

        return request;
    }

    /**
     * Processes the response for createE911Order.
     * @return An object of type Object
     */
    private ApiResponse<Object> handleCreateE911OrderResponse(
            HttpContext context) throws ApiException, IOException, JAXBException {
        HttpResponse response = context.getResponse();

        //invoke the callback after response if its not null
        if (getHttpCallback() != null) {
            getHttpCallback().onAfterResponse(context);
        }

        //Error handling using HTTP status codes
        int responseCode = response.getStatusCode();

        if (responseCode == 400) {
            throw new ApiException("Bad Request<br>A 400 response indicates that the order could not be created.<br>Error text and an error code will be provided in the ErrorList element.", context);
        }
        //handle errors defined at the API level
        validateResponse(response, context);

        //extract result from the http response
        String responseBody = ((HttpStringResponse) response).getBody();
        Object result = ApiHelper.deserializeXml(responseBody,
                Object.class);

        return new ApiResponse<Object>(response.getStatusCode(), response.getHeaders(), result);
    }

